rule.correct:
unawaited(Future(() async {
  try {
    await someCall();
  } catch (_) {}
}));

// ✅ Сохранить в локальную переменную перед closure
if (_endpoint == null) return;
final endpoint = _endpoint; // non-null локальная переменная
unawaited(Future(() async {
  await http.post(Uri.parse(endpoint)); // ✅ endpoint точно non-null
}));

rule.incorrect:
// ❌ _endpoint может быть null внутри closure
if (_endpoint == null) return;
unawaited(Future(() async {
  await http.post(Uri.parse(_endpoint!)); // ❌ нужен !
}));
